var geometry = new api.THREE.SphereGeometry(0.8, 24, 24);
                var material = new api.THREE.MeshPhongMaterial({ color: 0xE8593C });
                var testObject = new api.THREE.Mesh(geometry, material);
                api.group.add(testObject);
                return {
                  update: function(t) {
                    testObject.rotation.y = t * 0.02;
                    testObject.rotation.x = Math.sin(t * 0.01) * 0.3;
                  }
                };

var elapsed = 0;
        return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            var waterLevel = H * 0.5;
            ctx.fillStyle = 'rgba(59, 130, 246, 0.25)';
            ctx.fillRect(0, waterLevel, W, H - waterLevel);
            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(0, waterLevel);
            ctx.lineTo(W, waterLevel);
            ctx.stroke();

            var settleTime = 2.5;
            var holdTime = 1.5;
            var cycle = settleTime + holdTime;
            elapsed += Math.min(dt || 0, 0.05);
            if (elapsed > cycle) { elapsed -= cycle; }
            var progress = Math.min(elapsed / settleTime, 1);

            // Low-density object: sinks a little, then floats just under the surface
            var floatStartY = 40;
            var floatRestY = waterLevel - 15;
            var floatY = floatStartY + (floatRestY - floatStartY) * progress;
            ctx.fillStyle = '#F59E0B';
            ctx.beginPath();
            ctx.arc(W * 0.32, floatY, 16, 0, Math.PI * 2);
            ctx.fill();
            ctx.fillStyle = '#333';
            ctx.font = '12px Arial';
            ctx.fillText('low density: floats', W * 0.32 - 55, floatRestY + 40);

            // High-density object: sinks all the way to the bottom
            var sinkStartY = 40;
            var sinkRestY = H - 30;
            var sinkY = sinkStartY + (sinkRestY - sinkStartY) * progress;
            ctx.fillStyle = '#374151';
            ctx.beginPath();
            ctx.arc(W * 0.68, sinkY, 16, 0, Math.PI * 2);
            ctx.fill();
            ctx.fillStyle = '#333';
            ctx.fillText('high density: sinks', W * 0.68 - 55, sinkRestY + 20);

            ctx.fillStyle = '#333';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Same size, different density -> different result', 20, 25);
          }
        };

return {
          draw: function(ctx, w, h) {
            ctx.clearRect(0, 0, w, h);
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, w, h);

            var waterLevel = h * 0.45;
            ctx.fillStyle = 'rgba(59, 130, 246, 0.25)';
            ctx.fillRect(0, waterLevel, w, h - waterLevel);
            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(0, waterLevel);
            ctx.lineTo(w, waterLevel);
            ctx.stroke();

            var density = (state.density !== undefined) ? state.density : 0.8;
            var floats = density < 1.0;
            var submergedFraction = Math.min(Math.max(density, 0), 1);

            var ballRadius = 22;
            var ballY;
            if (floats) {
              ballY = waterLevel - ballRadius * (1 - submergedFraction * 2);
            } else {
              ballY = h - ballRadius - 20;
            }
            ballY = Math.max(ballRadius + 10, Math.min(h - ballRadius - 10, ballY));

            ctx.fillStyle = floats ? '#F59E0B' : '#374151';
            ctx.beginPath();
            ctx.arc(w / 2, ballY, ballRadius, 0, Math.PI * 2);
            ctx.fill();

            ctx.fillStyle = '#111827';
            ctx.font = 'bold 13px Arial';
            ctx.fillText('Density: ' + density.toFixed(2) + ' g/cm3 (water = 1.00)', 12, 22);
            ctx.font = '12px Arial';
            ctx.fillText(floats ? 'Result: FLOATS (less dense than water)' : 'Result: SINKS (denser than water)', 12, 40);
          },
          onControlChange: function(id, val) {
            state.density = val;
          },
          init: function() {
            state.density = 0.8;
          }
        };
